<?php $adminTitle='LMS Learners'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ $pdo->prepare('DELETE FROM learners WHERE id=?')->execute([(int)$_POST['id']]); header('Location: lms-learners.php'); exit; } $rows=$pdo->query('SELECT * FROM learners ORDER BY created_at DESC')->fetchAll(); ?><h1>Learners</h1><div class="glass-card"><table class="table table-dark"><tr><th>Name</th><th>Email</th><th>Phone</th><th>Joined</th><th></th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['full_name']); ?></td><td><?= e($r['email']); ?></td><td><?= e($r['phone']); ?></td><td><?= e($r['created_at']); ?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><input type="hidden" name="id" value="<?= (int)$r['id']; ?>"><button class="btn btn-sm btn-danger" onclick="return confirm('Delete learner?')">Delete/Disable</button></form></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>